$$
\begin{aligned}
&I=\frac{E}{A t}=\frac{n h v}{A t} \Rightarrow \frac{n}{t}=\frac{I A \lambda}{h C} \Rightarrow \frac{n}{t}=\frac{\rho \lambda}{h c} \Rightarrow \frac{n}{t}=\rho \lambda \\\\
&\Rightarrow\left(\frac{n}{t}\right)_{2}=\left(\frac{n}{t}\right)_{1} \times \frac{p_{2} \lambda_{2}}{p_{1} \lambda 1}=9 \times 10^{20} \times \frac{P}{P} \times \frac{800}{600}=12 \times 10^{20}
\end{aligned}
$$

Change in energy
<br/><br/>
$$
\begin{aligned}
&\Delta \mathrm{E}=\mathrm{E}_{\mathrm{f}}-\mathrm{E}_{2} \Rightarrow 12.09=\mathrm{E}_{\mathrm{f}}-(-13.6) \Rightarrow \mathrm{E}_{\mathrm{f}}=-1.51 \mathrm{eV} \\\\
&\Rightarrow \frac{-13.6}{n^{2}}=-1.51 \Rightarrow \mathrm{n}^{2}=9 \Rightarrow \mathrm{n}=3 \\\\
&\text { So, } \Delta \mathrm{L}=\mathrm{L}_{\mathrm{f}}-\mathrm{L}_{\mathrm{i}} \\\\
&=\frac{h}{2 \pi}(3-1)=\frac{2 h}{2 \pi}=\frac{h}{\pi}=\frac{6.63 \times 10^{-34}}{3.14}=2.11 \times 10^{-34} \mathrm{Js}
\end{aligned}
$$

$$
\begin{aligned}
& V_{a v}=\frac{S_{\text {total }}}{T_{\text {total }}}=\frac{200+200+\frac{2 \pi \times 200}{4}}{238} \\\\
&=\frac{400+100 \pi}{238}=\frac{714}{238}=3 \mathrm{~m} / \mathrm{s}
\end{aligned}
$$

Here, the apparent frequency is given by
<br/><br/>
$$
\begin{aligned}
&f^{\prime}=f\left(\frac{V-V_{0}}{V+V_{s}}\right)=720\left(\frac{(340+20)-20}{(340+20)-0}\right) \\\\
&=\frac{720 \times 340}{360}=680 \mathrm{~Hz}
\end{aligned}
$$

$I=\left(m_{A}+m_{B}+m_{C}+m_{D}\right) r^{2}$
<br/><br/>
$$
\begin{aligned}
&\mathrm{I}_{\text {net }}=(1+2+3+4) \cdot\left(\frac{a}{\sqrt{2}}\right)^{2} \text {, where a = side of square } \\\\
&=10 \times \frac{1^{2}}{2}=5 \mathrm{~kg} \mathrm{~m}^{2}
\end{aligned}
$$

As, $E_{n}=\frac{P \cdot E_{n}}{2}=-\frac{1.08}{2}=-0.544$
<br/><br/>
$$
\begin{aligned}
& \text { So, } \Delta \mathrm{E}, \mathrm{E}_{\mathrm{f}}-\mathrm{E}_{\mathrm{i}}=-0.544-\left(-\frac{13.6}{2^{2}}\right)=3.4-0.544 \\\\
& \approx 2.86 \mathrm{eV}=286 \times 10^{-2} \mathrm{eV}
\end{aligned}
$$

